<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Personal Expense Tracker</title>
<style>
  :root {
    --bg: #f5f6f8;
    --card: #ffffff;
    --border: #d9dde3;
    --text: #222;
    --muted: #667;
    --accent: #2563eb;
    --danger: #dc2626;
  }
  * { box-sizing: border-box; }
  body {
    font-family: system-ui, -apple-system, "Segoe UI", sans-serif;
    background: var(--bg);
    color: var(--text);
    margin: 0;
    padding: 1.5rem;
    display: flex;
    justify-content: center;
  }
  main { width: 100%; max-width: 640px; }
  h1 { font-size: 1.4rem; margin: 0 0 1rem; }
  section {
    background: var(--card);
    border: 1px solid var(--border);
    border-radius: 8px;
    padding: 1rem;
    margin-bottom: 1rem;
  }
  h2 { font-size: 1rem; margin: 0 0 .75rem; color: var(--muted); text-transform: uppercase; letter-spacing: .05em; }
  form .row, .filters .row {
    display: flex;
    flex-wrap: wrap;
    gap: .75rem;
    align-items: flex-end;
  }
  label {
    display: flex;
    flex-direction: column;
    font-size: .8rem;
    color: var(--muted);
    gap: .25rem;
    flex: 1 1 120px;
  }
  input, select, button {
    font: inherit;
    padding: .45rem .55rem;
    border: 1px solid var(--border);
    border-radius: 6px;
    background: #fff;
  }
  input:focus, select:focus { outline: 2px solid var(--accent); outline-offset: 1px; }
  button { cursor: pointer; }
  #add-expense {
    background: var(--accent);
    color: #fff;
    border-color: var(--accent);
    font-weight: 600;
    flex: 0 0 auto;
  }
  #form-error {
    color: var(--danger);
    font-size: .85rem;
    min-height: 1.2em;
    margin-top: .5rem;
  }
  .expense {
    display: flex;
    align-items: center;
    gap: .75rem;
    padding: .5rem .25rem;
    border-bottom: 1px solid var(--border);
  }
  .expense:last-child { border-bottom: none; }
  .expense .amt { font-weight: 600; min-width: 5.5em; text-align: right; }
  .expense .cat {
    background: #eef2ff;
    color: #3730a3;
    border-radius: 999px;
    padding: .1rem .6rem;
    font-size: .8rem;
    text-transform: capitalize;
  }
  .expense .dt { color: var(--muted); font-size: .85rem; min-width: 6.5em; }
  .expense .note { flex: 1; font-size: .85rem; color: var(--muted); overflow-wrap: anywhere; }
  .exp-del {
    background: #fff;
    color: var(--danger);
    border-color: var(--danger);
    padding: .2rem .55rem;
    font-size: .8rem;
  }
  .exp-del:hover { background: var(--danger); color: #fff; }
  .totals { display: flex; flex-wrap: wrap; gap: .5rem 1.25rem; align-items: baseline; }
  #total { font-size: 1.3rem; font-weight: 700; }
  .cat-total {
    font-size: .85rem;
    color: var(--muted);
    background: var(--bg);
    border-radius: 6px;
    padding: .2rem .55rem;
    text-transform: capitalize;
  }
  #empty-msg { color: var(--muted); font-size: .9rem; padding: .5rem .25rem; }
</style>
</head>
<body>
<main>
  <h1>Personal Expense Tracker</h1>

  <section>
    <h2>Add expense</h2>
    <form id="expense-form" novalidate>
      <div class="row">
        <label>Amount
          <input type="number" id="amount" step="0.01" min="0" placeholder="0.00">
        </label>
        <label>Category
          <select id="category">
            <option value="groceries">groceries</option>
            <option value="transport">transport</option>
            <option value="bills">bills</option>
            <option value="fun">fun</option>
          </select>
        </label>
        <label>Date
          <input type="date" id="date">
        </label>
        <label>Note (optional)
          <input type="text" id="note" placeholder="e.g. weekly shop">
        </label>
        <button type="submit" id="add-expense">Add</button>
      </div>
      <div id="form-error" role="alert"></div>
    </form>
  </section>

  <section class="filters">
    <h2>Filters</h2>
    <div class="row">
      <label>Category
        <select id="filter-category">
          <option value="all">all</option>
          <option value="groceries">groceries</option>
          <option value="transport">transport</option>
          <option value="bills">bills</option>
          <option value="fun">fun</option>
        </select>
      </label>
      <label>From
        <input type="date" id="filter-from">
      </label>
      <label>To
        <input type="date" id="filter-to">
      </label>
      <button type="button" id="clear-filters">Clear filters</button>
    </div>
  </section>

  <section>
    <h2>Summary (visible expenses)</h2>
    <div class="totals">
      <span id="total">0.00</span>
      <span class="cat-total" data-cat="groceries">groceries: 0.00</span>
      <span class="cat-total" data-cat="transport">transport: 0.00</span>
      <span class="cat-total" data-cat="bills">bills: 0.00</span>
      <span class="cat-total" data-cat="fun">fun: 0.00</span>
    </div>
  </section>

  <section>
    <h2>Expenses</h2>
    <div id="expense-list"></div>
    <div id="empty-msg" hidden>No expenses to show.</div>
  </section>
</main>

<script>
(function () {
  'use strict';

  var STORAGE_KEY = 'expense-tracker-expenses';
  var CATEGORIES = ['groceries', 'transport', 'bills', 'fun'];

  var form = document.getElementById('expense-form');
  var amountInput = document.getElementById('amount');
  var categoryInput = document.getElementById('category');
  var dateInput = document.getElementById('date');
  var noteInput = document.getElementById('note');
  var formError = document.getElementById('form-error');
  var listEl = document.getElementById('expense-list');
  var emptyMsg = document.getElementById('empty-msg');
  var totalEl = document.getElementById('total');
  var filterCategory = document.getElementById('filter-category');
  var filterFrom = document.getElementById('filter-from');
  var filterTo = document.getElementById('filter-to');
  var clearFiltersBtn = document.getElementById('clear-filters');

  var expenses = load();

  function load() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return [];
      var parsed = JSON.parse(raw);
      if (!Array.isArray(parsed)) return [];
      return parsed.filter(function (e) {
        return e && typeof e.amount === 'number' && isFinite(e.amount) &&
               typeof e.category === 'string' && typeof e.date === 'string';
      });
    } catch (err) {
      return [];
    }
  }

  function save() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
    } catch (err) { /* storage unavailable; keep working in-memory */ }
  }

  function isVisible(exp) {
    var cat = filterCategory.value;
    if (cat !== 'all' && exp.category !== cat) return false;
    var from = filterFrom.value;
    var to = filterTo.value;
    if (from && exp.date < from) return false;
    if (to && exp.date > to) return false;
    return true;
  }

  function render() {
    listEl.textContent = '';
    var visibleTotal = 0;
    var catTotals = {};
    CATEGORIES.forEach(function (c) { catTotals[c] = 0; });
    var visibleCount = 0;

    expenses.forEach(function (exp) {
      if (!isVisible(exp)) return;
      visibleCount++;
      visibleTotal += exp.amount;
      if (Object.prototype.hasOwnProperty.call(catTotals, exp.category)) {
        catTotals[exp.category] += exp.amount;
      } else {
        catTotals[exp.category] = exp.amount;
      }

      var row = document.createElement('div');
      row.className = 'expense';

      var amt = document.createElement('span');
      amt.className = 'amt';
      amt.textContent = exp.amount.toFixed(2);

      var cat = document.createElement('span');
      cat.className = 'cat';
      cat.textContent = exp.category;

      var dt = document.createElement('span');
      dt.className = 'dt';
      dt.textContent = exp.date;

      var note = document.createElement('span');
      note.className = 'note';
      note.textContent = exp.note || '';

      var del = document.createElement('button');
      del.type = 'button';
      del.className = 'exp-del';
      del.textContent = 'Delete';
      del.setAttribute('aria-label', 'Delete expense');
      del.addEventListener('click', function () {
        var idx = expenses.indexOf(exp);
        if (idx !== -1) {
          expenses.splice(idx, 1);
          save();
          render();
        }
      });

      row.appendChild(amt);
      row.appendChild(cat);
      row.appendChild(dt);
      row.appendChild(note);
      row.appendChild(del);
      listEl.appendChild(row);
    });

    emptyMsg.hidden = visibleCount > 0;
    totalEl.textContent = visibleTotal.toFixed(2);

    document.querySelectorAll('.cat-total').forEach(function (el) {
      var c = el.getAttribute('data-cat');
      var v = catTotals[c] || 0;
      el.textContent = c + ': ' + v.toFixed(2);
    });
  }

  form.addEventListener('submit', function (ev) {
    ev.preventDefault();

    var rawAmount = amountInput.value.trim();
    var amount = parseFloat(rawAmount);

    if (rawAmount === '' || isNaN(amount) || !isFinite(amount)) {
      formError.textContent = 'Please enter a valid numeric amount.';
      return;
    }
    if (amount <= 0) {
      formError.textContent = 'Amount must be greater than zero.';
      return;
    }
    if (!dateInput.value) {
      formError.textContent = 'Please choose a date.';
      return;
    }

    // Newest first: prepend to the list.
    expenses.unshift({
      amount: Math.round(amount * 100) / 100,
      category: categoryInput.value,
      date: dateInput.value,
      note: noteInput.value.trim()
    });
    save();

    formError.textContent = '';
    amountInput.value = '';
    noteInput.value = '';
    amountInput.focus();
    render();
  });

  filterCategory.addEventListener('change', render);
  filterFrom.addEventListener('change', render);
  filterFrom.addEventListener('input', render);
  filterTo.addEventListener('change', render);
  filterTo.addEventListener('input', render);

  clearFiltersBtn.addEventListener('click', function () {
    filterCategory.value = 'all';
    filterFrom.value = '';
    filterTo.value = '';
    render();
  });

  render();
})();
</script>
</body>
</html>
